    /**
     * @ignore
     * @method
     * @name binance#parseEvent
     * @description parses a raw binance market topic (with nested markets) into the unified event shape
     * @param {object} rawTopic the raw market topic object
     * @returns {object} an event structure
     */
    public virtual object parseEvent(object rawTopic)
    {
        //
        //     {
        //         "marketTopicId": 4229564,
        //         "vendor": "PREDICT_FUN",
        //         "chainId": "56",
        //         "slug": "btc-price-1h-up-or-down",
        //         "title": "BTC Price 1h Up or Down?",
        //         "question": "Will BTC price go UP?",
        //         "description": "Resolves YES if BTC spot price is higher than the starting price.",
        //         "imageUrl": "https://...",
        //         "topicType": "FLAT",
        //         "chartType": "CRYPTO_UP_DOWN",
        //         "symbol": "BTCUSDT",
        //         "variantData": { "type": "CRYPTO_UP_DOWN", "startPrice": "67890.12", "endPrice": null },
        //         "participantCount": 3420,
        //         "collateral": "USDT",
        //         "feeRateBps": 200,
        //         "slippageBps": 1200,
        //         "tradeVolume": "158234.56",
        //         "liquidity": "45000.00",
        //         "publishedAt": 1748100000000,
        //         "startDate": 1748131200000,
        //         "endDate": 1748134800000,
        //         "status": "REGISTERED",
        //         "timeline": [ ... ],
        //         "markets": [ { "marketId": 5567895, "title": "UP", "outcomes": [ ... ] } ]
        //     }
        //
        object rawMarkets = (IList<object>)(this.safeList(rawTopic, "markets", new List<object>() {}));
        object marketsList = new List<object>() {};
        object anyActive = false;
        object rawMarketsLength = getArrayLength(rawMarkets);
        for (object i = 0; isLessThan(i, rawMarketsLength); postFixIncrement(ref i))
        {
            object parsed = this.parseTopicMarket(getValue(rawMarkets, i), rawTopic);
            ((IList<object>)marketsList).Add(parsed);
            if (isTrue(this.safeBool(parsed, "active", false)))
            {
                anyActive = true;
            }
        }
        object topicId = this.safeString(rawTopic, "marketTopicId");
        object slug = this.safeString(rawTopic, "slug");
        object title = this.safeString(rawTopic, "title");
        object endDate = this.safeInteger(rawTopic, "endDate");
        object created = this.safeInteger2(rawTopic, "publishedAt", "startDate");
        object active = anyActive;
        if (isTrue(isEqual(rawMarketsLength, 0)))
        {
            object status = this.safeString(rawTopic, "status");
            active = isTrue((isEqual(status, "REGISTERED"))) || isTrue((isEqual(status, "OPEN")));
        }
        return new Dictionary<string, object>() {
            { "id", topicId },
            { "slug", slug },
            { "event", ((bool) isTrue((!isEqual(slug, null)))) ? this.shortenSlug(slug) : null },
            { "title", title },
            { "description", this.safeString(rawTopic, "description") },
            { "markets", marketsList },
            { "active", active },
            { "volume", this.safeNumber(rawTopic, "tradeVolume") },
            { "liquidity", this.safeNumber(rawTopic, "liquidity") },
            { "url", null },
            { "image", this.safeString(rawTopic, "imageUrl") },
            { "created", created },
            { "createdDatetime", this.iso8601(created) },
            { "end", endDate },
            { "endDatetime", this.iso8601(endDate) },
            { "category", this.safeString(rawTopic, "chartType") },
            { "resolved", null },
            { "info", rawTopic },
        };
    }

