        //         "decimalPrecision": 2,
        //         "outcomes": [
        //             { "name": "YES", "price": "0.52", "chance": "0.52", "index": 0, "tokenId": "112233" }
        //         ]
        //     }
        //
        object marketId = this.safeString(rawMarket, "marketId");
        object topicId = this.safeString(rawTopic, "marketTopicId");
        object topicSlug = this.safeString(rawTopic, "slug");
        object vendor = this.safeString(rawTopic, "vendor");
        object collateral = this.safeString(rawTopic, "collateral", "USDT");
        object title = this.safeString(rawMarket, "title", marketId);
        object marketSymbol = this.slugToMarketSymbol(topicSlug, title);
        object tradingStatus = this.safeString(rawMarket, "tradingStatus");
        object status = this.safeString(rawMarket, "status");
        object active = (isEqual(tradingStatus, "OPEN"));
        if (isTrue(isEqual(tradingStatus, null)))
        {
            active = isTrue((isEqual(status, "REGISTERED"))) || isTrue((isEqual(status, "OPEN")));
        }
        object resolved = isTrue((isEqual(status, "RESOLVED"))) || isTrue((isEqual(status, "SETTLED")));
        object endDate = this.safeInteger(rawTopic, "endDate");
        object feeRateBps = this.safeString(rawTopic, "feeRateBps", "200");
        object feeRate = this.parseNumber(Precise.stringDiv(feeRateBps, "10000"));
        object decimalPrecision = this.safeString(rawMarket, "decimalPrecision", "2");
        object pricePrecision = this.parseNumber(this.parsePrecision(decimalPrecision));
        object precision = new Dictionary<string, object>() {
            { "amount", null },
            { "price", pricePrecision },
        };
        object volume = this.safeNumber(rawMarket, "tradeVolume");
        object liquidity = this.safeNumber(rawMarket, "liquidity");
        object rawOutcomes = (IList<object>)(this.safeList(rawMarket, "outcomes", new List<object>() {}));
        object outcomes = new List<object>() {};
        object resolvedOutcomeRaw = null;
        object rawOutcomesLength = getArrayLength(rawOutcomes);
        for (object oi = 0; isLessThan(oi, rawOutcomesLength); postFixIncrement(ref oi))
        {
            object rawOutcome = getValue(rawOutcomes, oi);
            object label = this.safeStringUpper(rawOutcome, "name");
            object tokenId = this.safeString(rawOutcome, "tokenId");
            object outcomeHandle = this.slugToOutcomeSymbol(topicSlug, title, label);
            object price = this.safeString(rawOutcome, "price");
            object winnerRaw = null;
            object settleFractionRaw = null;
            if (isTrue(isTrue(resolved) && isTrue((!isEqual(price, null)))))
            {
                winnerRaw = Precise.stringEq(price, "1");
                settleFractionRaw = ((bool) isTrue((winnerRaw))) ? 1 : 0;
                if (isTrue(winnerRaw))
                {
                    resolvedOutcomeRaw = outcomeHandle;
                }
            }
            object winner = winnerRaw;
            object settleFraction = settleFractionRaw;
            ((IList<object>)outcomes).Add(new Dictionary<string, object>() {
                { "id", tokenId },
                { "outcomeId", tokenId },
                { "outcome", outcomeHandle },
                { "market", marketSymbol },
                { "label", label },
                { "active", active },
                { "winner", winner },
                { "settleFraction", settleFraction },
                { "precision", precision },
                { "info", new Dictionary<string, object>() {
                    { "tokenId", tokenId },
                    { "marketId", marketId },
                    { "marketTopicId", topicId },
                    { "vendor", vendor },
                    { "chainId", this.safeString(rawTopic, "chainId") },
                    { "slug", topicSlug },
                    { "marketTitle", title },
                    { "outcomeLabel", label },
                    { "index", this.safeString(rawOutcome, "index") },
                    { "price", price },
                    { "chance", this.safeString(rawOutcome, "chance") },
                    { "collateral", collateral },
                    { "feeRateBps", feeRateBps },
                    { "slippageBps", this.safeString(rawTopic, "slippageBps") },
                    { "conditionId", this.safeString(rawMarket, "conditionId") },
                    { "externalId", this.safeString(rawMarket, "externalId") },
                } },
            });
        }
        object resolvedOutcome = resolvedOutcomeRaw;
        return new Dictionary<string, object>() {
            { "id", marketId },
            { "market", marketSymbol },
            { "base", collateral },
            { "quote", collateral },
            { "settle", null },
            { "baseId", marketId },
            { "quoteId", collateral },
            { "settleId", null },
            { "type", "prediction" },
            { "marketType", "binary" },
            { "executionModel", "clob" },
            { "spot", false },
            { "margin", false },
            { "swap", false },
            { "future", false },
            { "option", false },
            { "prediction", true },
            { "active", active },
            { "resolved", resolved },
            { "resolvedOutcome", resolvedOutcome },
            { "contract", false },
            { "linear", null },
            { "inverse", null },
            { "contractSize", null },
            { "expiry", endDate },
            { "expiryDatetime", this.iso8601(endDate) },
            { "strike", null },
            { "optionType", null },
            { "taker", feeRate },
            { "maker", feeRate },
            { "percentage", true },
            { "tierBased", false },
            { "feeSide", "get" },
            { "precision", precision },
            { "limits", new Dictionary<string, object>() {
                { "leverage", new Dictionary<string, object>() {
                    { "min", 1 },
                    { "max", 1 },
                } },
                { "amount", new Dictionary<string, object>() {
                    { "min", null },
                    { "max", null },
                } },
                { "price", new Dictionary<string, object>() {
                    { "min", 0.01 },
                    { "max", 0.99 },
                } },
                { "cost", new Dictionary<string, object>() {
                    { "min", 1.5 },
                    { "max", null },
                } },
            } },
            { "outcomes", outcomes },
            { "info", this.extend(rawMarket, new Dictionary<string, object>() {
                { "marketTopicId", topicId },
                { "vendor", vendor },
                { "slug", topicSlug },
                { "volume", volume },
                { "liquidity", liquidity },
            }) },
            { "created", this.safeInteger(rawTopic, "publishedAt") },
        };
    }

    /**
     * @method
     * @name binance#fetchTicker
     * @description fetches the last trade price for a single prediction outcome
     * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
     * @param {string} outcome unified outcome handle like BTC_PRICE_1H_UP_DOWN_UP:YES, or an outcome token id
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a prediction [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public async override Task<object> fetchTicker(object outcome, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadOutcome(outcome);
        object outcomeObj = this.outcome(outcome);
        object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
        object request = new Dictionary<string, object>() {
            { "marketId", this.safeString(info, "marketId") },
        };
        object response = await this.sapiPrivateGetOrderBookLastTradePrice(this.extend(request, parameters));
        //
        //     { "marketId": 5567895, "lastTradePrice": "0.52" }
        //
        return this.parsePredictionTicker(response, ((object)outcomeObj));
    }

    /**
     * @ignore
     * @method
     * @name binance#parsePredictionTicker
     * @description parses a last-trade-price response into a unified ticker object; the venue quotes the market's primary (YES) token, so a NO outcome mirrors as 1 - price
     * @param {object} raw the raw last-trade-price object
     * @param {object} [market] the outcome object the ticker belongs to
     * @returns {object} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public override object parsePredictionTicker(object raw, object market = null)
    {
        //
        //     { "marketId": 5567895, "lastTradePrice": "0.52" }
        //
        object marketAny = ((object)market);
        object outcomeObj = this.safeOutcome(this.safeString(marketAny, "outcome"), marketAny);
        object label = this.safeStringUpper(outcomeObj, "label", "YES");
        object isNo = (isEqual(label, "NO"));
        object lastString = this.safeString(raw, "lastTradePrice");
        object last = null;
        if (isTrue(!isEqual(lastString, null)))
        {
            if (isTrue(isNo))
            {
                last = this.parseNumber(Precise.stringSub("1", lastString));
            } else
            {
                last = this.parseNumber(lastString);
            }
        }
        object now = this.milliseconds();
        return this.safePredictionTicker(new Dictionary<string, object>() {
            { "outcome", this.safeString(outcomeObj, "outcome") },
            { "outcomeId", this.safeString2(outcomeObj, "outcomeId", "id") },
            { "label", this.safeString(outcomeObj, "label") },
            { "market", this.safeString(outcomeObj, "market") },
            { "timestamp", now },
            { "datetime", this.iso8601(now) },
            { "high", null },
            { "low", null },
            { "bid", null },
            { "bidVolume", null },
            { "ask", null },
            { "askVolume", null },
            { "vwap", null },
            { "open", null },
            { "close", last },
            { "last", last },
            { "previousClose", null },
            { "change", null },
            { "percentage", null },
            { "average", null },
            { "baseVolume", null },
            { "quoteVolume", null },
            { "info", raw },
        }, market);
    }

    /**
     * @method
     * @name binance#fetchTickers
     * @description fetches last trade prices for multiple outcomes, one request per distinct underlying market
     * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
     * @param {string[]} outcomes unified outcomes — required: the venue has no all-tickers endpoint
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of prediction [ticker structures](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public async override Task<object> fetchTickers(object outcomes = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        if (isTrue(isEqual(outcomes, null)))
        {
            throw new ArgumentsRequired ((string)add(this.id, " fetchTickers() requires an outcomes argument — the venue has no all-tickers endpoint; pass the outcome handles to fetch (discover them via fetchEvents ())")) ;
        }
        await this.loadOutcomes(outcomes);
        object responsesByMarketId = new Dictionary<string, object>() {};
        object result = new Dictionary<string, object>() {};
        object outcomesLength = getArrayLength(outcomes);
        for (object i = 0; isLessThan(i, outcomesLength); postFixIncrement(ref i))
        {
            object outcomeObj = this.outcome(getValue(outcomes, i));
            object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
            object marketId = this.safeString(info, "marketId");
            if (isTrue(isEqual(marketId, null)))
            {
                continue;
            }
            object response = this.safeDict(responsesByMarketId, marketId);
            if (isTrue(isEqual(response, null)))
            {
                object request = new Dictionary<string, object>() {
                    { "marketId", marketId },
                };
                response = await this.sapiPrivateGetOrderBookLastTradePrice(this.extend(request, parameters));
                ((IDictionary<string,object>)responsesByMarketId)[(string)marketId] = response;
            }
            object ticker = this.parsePredictionTicker(response, ((object)outcomeObj));
            object symbolKey = this.safeString(ticker, "outcome", getValue(outcomes, i));
            ((IDictionary<string,object>)result)[(string)symbolKey] = ticker;
        }
        return result;
    }

    /**
     * @method
     * @name binance#fetchOrderBook
     * @description fetches the order book for a single prediction outcome token
     * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
     * @param {string} outcome unified outcome handle, or an outcome token id
     * @param {int} [limit] not used by binance fetchOrderBook
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a prediction [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
     */
    public async override Task<object> fetchOrderBook(object outcome, object limit = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadOutcome(outcome);
        object outcomeObj = this.outcome(outcome);
        object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
        object request = new Dictionary<string, object>() {
            { "vendor", this.safeString(info, "vendor", this.safeString(this.options, "defaultVendor")) },
            { "marketId", this.safeString(info, "marketId") },
            { "tokenId", this.safeString2(outcomeObj, "outcomeId", "id") },
        };
        object response = await this.sapiPrivateGetOrderBook(this.extend(request, parameters));
        //
        //     {
        //         "outcome": "YES",
        //         "tokenId": "112233",
        //         "timestamp": 1748131800000,
        //         "bids": [ { "price": "0.51", "size": "5000.00" } ],
        //         "asks": [ { "price": "0.52", "size": "3000.00" } ]
        //     }
        //
        object timestamp = this.safeInteger(response, "timestamp");
        object orderbook = this.parseOrderBook(response, this.safeOutcomeSymbol(outcome, outcomeObj), timestamp, "bids", "asks", "price", "size");
        return this.safePredictionOrderBook(orderbook, outcomeObj);
    }

    public override object handleErrors(object code, object reason, object url, object method, object headers, object body, object response, object requestHeaders, object requestBody)
    {
        if (isTrue(isEqual(response, null)))
        {
            return null;
        }
        object errorCode = this.safeString(response, "code");
        if (isTrue(isTrue((!isEqual(errorCode, null))) && isTrue(Precise.stringLt(errorCode, "0"))))
        {
            object message = this.safeString(response, "msg", "");
            object feedback = add(add(this.id, " "), body);
            this.throwExactlyMatchedException(getValue(this.exceptions, "exact"), errorCode, feedback);
            this.throwBroadlyMatchedException(getValue(this.exceptions, "broad"), message, feedback);
            throw new ExchangeError ((string)feedback) ;
        }
        return null;
    }

    /**
     * @ignore
     * @method
     * @name binance#sign
     * @description builds the request URL and attaches the standard binance SAPI HMAC-SHA256 signature — every prediction endpoint is signed
     * @param {string} path the endpoint path
     * @param {string|string[]} [api] the api group and access level
     * @param {string} [method] HTTP method
     * @param {object} [params] request parameters
     * @param {object} [headers] request headers
     * @param {object} [body] request body
     * @returns {object} a dictionary with url, method, body and headers
     */
    public override object sign(object path, object api = null, object method = null, object parameters = null, object headers = null, object body = null)
    {
        api ??= "sapi";
        method ??= "GET";
        parameters ??= new Dictionary<string, object>();
        object apiGroup = ((bool) isTrue((api is string))) ? api : getValue(api, 0);
        object baseUrls = getValue(this.urls, "api");
        object baseUrl = this.safeString(baseUrls, apiGroup, ((string)getValue(baseUrls, "sapi")));
        object url = add(add(baseUrl, "/"), this.implodeParams(path, parameters));
        object query = this.omit(parameters, this.extractParams(path));
        this.checkRequiredCredentials();
        object extendedParams = this.extend(new Dictionary<string, object>() {
            { "timestamp", this.nonce() },
        }, query);
        object defaultRecvWindow = this.safeInteger(this.options, "recvWindow");
        if (isTrue(!isEqual(defaultRecvWindow, null)))
        {
            ((IDictionary<string,object>)extendedParams)["recvWindow"] = defaultRecvWindow;
        }
        object querystring = this.urlencode(extendedParams);
        object signature = this.hmac(this.encode(querystring), this.encode(this.secret), sha256);
        querystring = add(add(querystring, "&signature="), signature);
        headers = new Dictionary<string, object>() {
            { "X-MBX-APIKEY", this.apiKey },
        };
        if (isTrue(isTrue((isEqual(method, "GET"))) || isTrue((isEqual(method, "DELETE")))))
        {
            url = add(add(url, "?"), querystring);
        } else
        {
            body = querystring;
            ((IDictionary<string,object>)headers)["Content-Type"] = "application/x-www-form-urlencoded";
        }
        return new Dictionary<string, object>() {
            { "url", url },
            { "method", method },
            { "body", body },
            { "headers", headers },
        };
    }
